  "#94a3b8": { en: "Silver", fr: "Argent" },
  "#4a4a4a": { en: "Charcoal", fr: "Charbon" },
  "#6b8bb0": { en: "Solace Blue", fr: "Bleu Solace" },
  "#7dd3fc": { en: "Light Blue", fr: "Bleu clair" },
  "#b8b8b8": { en: "Grey Heather", fr: "Gris chiné" },
